const raw = $input.item.json.body || $input.item.json;

return [{
  json: {
    ticket_id: raw.ticket_id || ('TKT-' + Date.now()),
    channel: raw.channel || 'web',
    customer_name: raw.customer_name || 'Unknown Customer',
    customer_email: raw.customer_email || '',
    customer_tier: raw.customer_tier || 'standard',
    account_value: raw.account_value || '$0',
    subject: raw.subject || 'No subject',
    message: raw.message || '',
    prior_tickets_30d: raw.prior_tickets_30d || 0,
    received_at: new Date().toISOString()
  }
}];

const t = $('Normalize Ticket').item.json;
const prompt = `You are an expert customer support triage specialist. Analyze this support ticket and return structured JSON.

TICKET:
---
Ticket ID: ${t.ticket_id}
Channel: ${t.channel}
Customer: ${t.customer_name} (${t.customer_tier})
Subject: ${t.subject}
Message: ${t.message}
Account Value: ${t.account_value}
Prior Tickets (30d): ${t.prior_tickets_30d}
---

Return ONLY valid JSON:
{
  "priority": "CRITICAL" | "URGENT" | "HIGH" | "STANDARD" | "LOW",
  "category": "billing" | "technical" | "account_management" | "product_bug" | "feature_request" | "onboarding" | "cancellation_risk" | "general",
  "sentiment": "angry" | "frustrated" | "neutral" | "satisfied" | "confused",
  "vip_customer": true | false,
  "churn_risk": "high" | "medium" | "low" | "none",
  "assigned_team": "billing_team" | "tier1_support" | "tier2_technical" | "account_management" | "retention_team" | "product_team",
  "sla_hours": 1 | 2 | 4 | 8 | 24 | 48,
  "auto_response": "2-3 sentence professional first response to send immediately. Acknowledge their issue specifically, set expectation for resolution. Do not make promises about outcomes. Use their name.",
  "agent_summary": "2-3 sentence internal brief for the assigned agent: key issue, risk flags, recommended first action.",
  "tags": ["array", "of", "relevant", "tags"],
  "reasoning": "1-2 sentence explanation of priority and routing decision"
}

Priority rules:
- CRITICAL: Cancellation threat, complete service outage, data loss, payment failure on large account
- URGENT: Significant business impact, VIP customer any issue, billing error >$500, security concern
- HIGH: Partial service degradation, billing questions, account changes
- STANDARD: General questions, feature requests, minor bugs
- LOW: Compliments, general feedback, non-urgent feature requests

VIP = account_value > $10,000/yr OR customer_tier === "enterprise" OR customer_tier === "platinum"
Churn risk = high if cancellation language, repeated issues, or angry + CRITICAL/URGENT`;

return [{ json: { ...t, prompt } }];

const response = $('Claude: Classify & Draft').item.json;
const content = (response.choices && response.choices[0] && response.choices[0].message && response.choices[0].message.content) ? response.choices[0].message.content : '';
const ticket = $('Normalize Ticket').item.json;

let parsed;
try {
  const match = content.match(/\{[\s\S]*\}/);
  parsed = JSON.parse(match ? match[0] : content);
} catch(e) {
  parsed = {
    priority: 'STANDARD',
    category: 'general',
    sentiment: 'neutral',
    vip_customer: false,
    churn_risk: 'none',
    assigned_team: 'tier1_support',
    sla_hours: 8,
    auto_response: 'Hi ' + ticket.customer_name + ', thank you for reaching out. We\'ve received your ticket and a specialist will be in touch within 8 hours.',
    agent_summary: 'AI parse failed — manual review required.',
    tags: [],
    reasoning: 'Fallback to standard routing due to AI parse error.'
  };
}

return [{
  json: {
    ticket_id: ticket.ticket_id,
    channel: ticket.channel,
    customer_name: ticket.customer_name,
    customer_email: ticket.customer_email,
    customer_tier: ticket.customer_tier,
    account_value: ticket.account_value,
    subject: ticket.subject,
    message: ticket.message,
    prior_tickets_30d: ticket.prior_tickets_30d,
    received_at: ticket.received_at,
    priority: parsed.priority,
    category: parsed.category,
    sentiment: parsed.sentiment,
    vip_customer: parsed.vip_customer,
    churn_risk: parsed.churn_risk,
    assigned_team: parsed.assigned_team,
    sla_hours: parsed.sla_hours,
    auto_response: parsed.auto_response,
    agent_summary: parsed.agent_summary,
    tags: parsed.tags,
    reasoning: parsed.reasoning,
    processing_timestamp: new Date().toISOString()
  }
}];
